from collections import deque

class MonotoneCHT:
    """
    Maintains lower convex hull for lines y = m*x + b.
    Assumes lines added in DECREASING slope order.
    Assumes queries made in INCREASING x order.
    """
    def __init__(self):
        self.hull = deque()  # each entry: (m, b)

    def _bad(self, l1, l2, l3):
        # l2 is never the minimum if l1 and l3 intersect at x <= l1,l2 intersection
        m1,b1 = l1; m2,b2 = l2; m3,b3 = l3
        return (b3 - b1) * (m1 - m2) <= (b2 - b1) * (m1 - m3)

    def add_line(self, m, b):
        new_line = (m, b)
        while len(self.hull) >= 2 and self._bad(self.hull[-2], self.hull[-1], new_line):
            self.hull.pop()
        self.hull.append(new_line)

    def query(self, x):
        # Pop front while next line is better (monotone increasing x)
        while len(self.hull) >= 2:
            m1,b1 = self.hull[0]; m2,b2 = self.hull[1]
            if m1*x + b1 >= m2*x + b2:
                self.hull.popleft()
            else:
                break
        m, b = ___________
        return m * x + b
